class Solution:
    def shortestAlternatingPaths(self, n: int, redEdges: List[List[int]], blueEdges: List[List[int]]) -> List[int]:
        graph = [[] for _ in range(n)]
        for edge in redEdges:
            graph[edge[0]].append((edge[1], 0))
        for edge in blueEdges:
            graph[edge[0]].append((edge[1], 1))
        distance = [float('inf')] * n
        distance[0] = 0
        queue = [(0, 0)]
        while queue:
            node, color = queue.pop(0)
            for neighbor, edge_color in graph[node]:
                if edge_color != color:
                    if distance[neighbor] > distance[node] + 1:
                        distance[neighbor] = distance[node] + 1
                        queue.append((neighbor, 1 - color))
        return [distance[i] if distance[i] != float('inf') else -1 for i in range(n)]
